#!/usr/bin/env python3
"""
Cuando se marca una cita como 'Completada', ahora se envia un correo
al cliente invitandolo a calificar su experiencia, con un boton que
lo lleva a /p/[slug]/cita/[id] (donde aparece el formulario de resena).
Antes, marcar una cita como completada no enviaba ningun correo.

Ejecutar desde la raiz del repo (carpeta que contiene 'src'):
    python3 apply_completed_review_email.py
"""

import base64
from pathlib import Path

FILES = {
    'src/lib/appointmentEmails.ts': """""",
    'src/components/AppointmentsClient.tsx': """""",
}

def main():
    for relpath, b64 in FILES.items():
        p = Path(relpath)
        p.write_bytes(base64.b64decode(b64))
        print(f"escrito: {relpath} ({p.stat().st_size} bytes)")
    print()
    print("Listo. Luego:")
    print("  git add -A")
    print("  git commit -m 'Email de invitacion a resena al completar una cita'")
    print("  git push")

if __name__ == "__main__":
    main()